const input = $input.first().json;
const body = input.body ?? input;
const file = body.file ?? {};
const options = body.options ?? {};
const action = body.action ?? 'legenda';
const model = body.model ?? 'gemini-2.0-flash-lite-001';
const prompt = body.prompt ?? 'Generate a concise social media caption in Brazilian Portuguese. Return only valid JSON.';
const systemInstruction = body.systemInstruction ?? 'You are a senior Brazilian social media strategist. Return only valid JSON.';

const parts = [{ text: `${systemInstruction}\n\n${prompt}` }];

if (file.base64 && file.mimeType) {
  parts.push({
    inline_data: {
      mime_type: file.mimeType,
      data: file.base64
    }
  });
}

return [{
  json: {
    action,
    model,
    requestMeta: {
      platform: options.platform,
      mimeType: file.mimeType,
      fileName: file.name
    },
    geminiRequest: {
      contents: [{ role: 'user', parts }],
      generationConfig: {
        temperature: 0.35,
        responseMimeType: 'application/json'
      }
    }
  }
}];

const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text ?? '{}';
let parsed;
try {
  parsed = typeof text === 'string' ? JSON.parse(text) : text;
} catch (error) {
  parsed = { caption: String(text) };
}

const caption = parsed.caption ?? parsed.transcription ?? parsed.text ?? '';
const transcription = parsed.transcription ?? caption;
const hashtags = Array.isArray(parsed.hashtags) ? parsed.hashtags : [];

return [{
  json: {
    ...parsed,
    caption,
    transcription,
    hashtags,
    ok: true
  }
}];
